import React, { useEffect, useState } from "react";
import { useHistory, useParams } from "react-router";
import styled from "styled-components";
import "./Detail.scss";

let Boxmodel = styled.div`
  padding: 20px;
`;
let Titlemodel = styled.h4`
  font-size: 25px;
  color: ${(props) => props.color};
`;
function Detail({ shoes, inven, setInven }) {
  const [alert, setAlert] = useState(true);
  const [inputData, setInputData] = useState("");
  useEffect(() => {
    const timer = setTimeout(() => {
      setAlert(false);
    }, 2000);
  }, [alert]);

  const history = useHistory();
  const { id } = useParams();
  const findItem = shoes.find((item) => (item.id = id));

  return (
    <div className="container">
      <Boxmodel>
        <Titlemodel className="red">Hello</Titlemodel>
      </Boxmodel>

      <input
        onChange={(e) => {
          setInputData(e.target.value);
        }}
      />
      {inputData}
      {alert === true ? (
        <div className="my-alert2">
          <p>재고가 얼마 남지 않았습니다!</p>
        </div>
      ) : null}

      <div className="row">
        <div className="col-md-6">
          <img
            src="https://codingapple1.github.io/shop/shoes1.jpg"
            width="100%"
            alt="ShowImage"
          />
        </div>
        <div className="col-md-6 mt-4">
          <h4 className="pt-5">{findItem.Boxmodel}</h4>
          <p>{findItem.content}</p>
          <p>{findItem.price}</p>
          <Info inven={inven} />
          <button
            className="btn btn-danger"
            onClick={() => {
              setInven([9, 11, 12]);
            }}
          >
            주문하기
          </button>

          <button
            className="btn btn-danger"
            onClick={() => {
              history.push("/"); //history.goBack();
            }}
          >
            뒤로가기
          </button>
        </div>
      </div>
    </div>
  );
}
function Info({ inven }) {
  return <p>{inven[0]}</p>;
}

export default Detail;
